using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = "";

    [LoadColumn(1)]
    public string Description { get; set; } = "";

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = "";
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = "";

    public float[] Score { get; set; } = [];
}

using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public record ClassifierMetadata(string[] Labels);

public static class ModelTrainer
{
    public static (ClassifierMetadata Metadata, MulticlassClassificationMetrics Metrics) TrainAndEvaluate(
        string dataPath, string modelPath)
    {
        var mlContext = new MLContext(seed: 42);

        var data = mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = mlContext.Transforms.Text
                .FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject))
            .Append(mlContext.Transforms.Text
                .FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category)))
            .Append(mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        var model = pipeline.Fit(split.TrainSet);
        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions);

        // Extract label names from the Score column's slot names
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        predictions.Schema["Score"].GetSlotNames(ref slotNames);
        var values = slotNames.GetValues().ToArray();
        var labels = Array.ConvertAll(values, v => v.ToString());

        mlContext.Model.Save(model, data.Schema, modelPath);

        return (new ClassifierMetadata(labels), metrics);
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _predictionPool;
    private readonly ClassifierMetadata _metadata;

    public TicketsController(
        PredictionEnginePool<TicketData, TicketPrediction> predictionPool,
        ClassifierMetadata metadata)
    {
        _predictionPool = predictionPool;
        _metadata = metadata;
    }

    [HttpPost("classify")]
    public ActionResult<ClassifyResponse> Classify([FromBody] ClassifyRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketData
        {
            Subject = request.Subject ?? "",
            Description = request.Description ?? "",
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < _metadata.Labels.Length && i < prediction.Score.Length; i++)
            confidence[_metadata.Labels[i]] = prediction.Score[i];

        return Ok(new ClassifyResponse(prediction.Category, confidence));
    }
}

public record ClassifyRequest(string? Subject, string? Description, int Priority);
public record ClassifyResponse(string PredictedCategory, Dictionary<string, float> Confidence);

