using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
var modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");

var (metadata, metrics) = ModelTrainer.TrainAndEvaluate(dataPath, modelPath);

builder.Services.AddSingleton(metadata);
builder.Services.AddPredictionEnginePool<TicketData, TicketPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.Logger.LogInformation(
    "Model trained — MicroAccuracy: {Micro:F4}, MacroAccuracy: {Macro:F4}, LogLoss: {LogLoss:F4}",
    metrics.MicroAccuracy, metrics.MacroAccuracy, metrics.LogLoss);

app.MapControllers();
app.Run();

